// LoadExternalTask allows an eager lookup of values, cached into the
// loaded structs of the objects. This is for an N-1 relationship.
func (rawBatchL) LoadExternalTask(ctx context.Context, e boil.ContextExecutor, singular bool, maybeRawBatch any, mods queries.Applicator) error {
	var slice []*RawBatch
	var object *RawBatch

	if singular {
		var ok bool
		object, ok = maybeRawBatch.(*RawBatch)
		if !ok {
			object = new(RawBatch)
			ok = queries.SetFromEmbeddedStruct(&object, &maybeRawBatch)
			if !ok {
				return errors.New(fmt.Sprintf("failed to set %T from embedded struct %T", object, maybeRawBatch))
			}
		}
	} else {
		s, ok := maybeRawBatch.(*[]*RawBatch)
		if ok {
			slice = *s
		} else {
			ok = queries.SetFromEmbeddedStruct(&slice, maybeRawBatch)
			if !ok {
				return errors.New(fmt.Sprintf("failed to set %T from embedded struct %T", slice, maybeRawBatch))
			}
		}
	}

	args := make(map[any]struct{})
	if singular {
		if object.R == nil {
			object.R = &rawBatchR{}
		}
		if !queries.IsNil(object.ExternalTaskID) {
			args[object.ExternalTaskID] = struct{}{}
		}

	} else {
		for _, obj := range slice {
			if obj.R == nil {
				obj.R = &rawBatchR{}
			}

			if !queries.IsNil(obj.ExternalTaskID) {
				args[obj.ExternalTaskID] = struct{}{}
			}

		}
	}

	if len(args) == 0 {
		return nil
	}

	argsSlice := make([]any, len(args))
	i := 0
	for arg := range args {
		argsSlice[i] = arg
		i++
	}

	query := NewQuery(
		qm.From(`ingest.external_tasks`),
		qm.WhereIn(`ingest.external_tasks.id in ?`, argsSlice...),
	)
	if mods != nil {
		mods.Apply(query)
	}

	results, err := query.QueryContext(ctx, e)
	if err != nil {
		return errors.Wrap(err, "failed to eager load ExternalTask")
	}

	var resultSlice []*ExternalTask
	if err = queries.Bind(results, &resultSlice); err != nil {
		return errors.Wrap(err, "failed to bind eager loaded slice ExternalTask")
	}

	if err = results.Close(); err != nil {
		return errors.Wrap(err, "failed to close results of eager load for external_tasks")
	}
	if err = results.Err(); err != nil {
		return errors.Wrap(err, "error occurred during iteration of eager loaded relations for external_tasks")
	}

	if len(externalTaskAfterSelectHooks) != 0 {
		for _, obj := range resultSlice {
			if err := obj.doAfterSelectHooks(ctx, e); err != nil {
				return err
			}
		}
	}

	if len(resultSlice) == 0 {
		return nil
	}

	if singular {
		foreign := resultSlice[0]
		object.R.ExternalTask = foreign
		if foreign.R == nil {
			foreign.R = &externalTaskR{}
		}
		foreign.R.RawBatches = append(foreign.R.RawBatches, object)
		return nil
	}

	for _, local := range slice {
		for _, foreign := range resultSlice {
			if queries.Equal(local.ExternalTaskID, foreign.ID) {
				local.R.ExternalTask = foreign
				if foreign.R == nil {
					foreign.R = &externalTaskR{}
				}
				foreign.R.RawBatches = append(foreign.R.RawBatches, local)
				break
			}
		}
	}

	return nil
}

