// SetExternalTask of the rawBatch to the related item.
// Sets o.R.ExternalTask to related.
// Adds o to related.R.RawBatches.
func (o *RawBatch) SetExternalTask(ctx context.Context, exec boil.ContextExecutor, insert bool, related *ExternalTask) error {
	var err error
	if insert {
		if err = related.Insert(ctx, exec, boil.Infer()); err != nil {
			return errors.Wrap(err, "failed to insert into foreign table")
		}
	}

	updateQuery := fmt.Sprintf(
		"UPDATE \"ingest\".\"raw_batches\" SET %s WHERE %s",
		strmangle.SetParamNames("\"", "\"", 1, []string{"external_task_id"}),
		strmangle.WhereClause("\"", "\"", 2, rawBatchPrimaryKeyColumns),
	)
	values := []any{related.ID, o.ID}

	if boil.IsDebug(ctx) {
		writer := boil.DebugWriterFrom(ctx)
		fmt.Fprintln(writer, updateQuery)
		fmt.Fprintln(writer, values)
	}
	if _, err = exec.ExecContext(ctx, updateQuery, values...); err != nil {
		return errors.Wrap(err, "failed to update local table")
	}

	queries.Assign(&o.ExternalTaskID, related.ID)
	if o.R == nil {
		o.R = &rawBatchR{
			ExternalTask: related,
		}
	} else {
		o.R.ExternalTask = related
	}

	if related.R == nil {
		related.R = &externalTaskR{
			RawBatches: RawBatchSlice{o},
		}
	} else {
		related.R.RawBatches = append(related.R.RawBatches, o)
	}

	return nil
}

// RemoveExternalTask relationship.
// Sets o.R.ExternalTask to nil.
// Removes o from all passed in related items' relationships struct.
func (o *RawBatch) RemoveExternalTask(ctx context.Context, exec boil.ContextExecutor, related *ExternalTask) error {
	var err error

	queries.SetScanner(&o.ExternalTaskID, nil)
	if _, err = o.Update(ctx, exec, boil.Whitelist("external_task_id")); err != nil {
		return errors.Wrap(err, "failed to update local table")
	}

	if o.R != nil {
		o.R.ExternalTask = nil
	}
	if related == nil || related.R == nil {
		return nil
	}

	for i, ri := range related.R.RawBatches {
		if queries.Equal(o.ExternalTaskID, ri.ExternalTaskID) {
			continue
		}

		ln := len(related.R.RawBatches)
		if ln > 1 && i < ln-1 {
			related.R.RawBatches[i] = related.R.RawBatches[ln-1]
		}
		related.R.RawBatches = related.R.RawBatches[:ln-1]
		break
	}
	return nil
}

